/**
 * @summary Top requesters this week
 */
export const getGetTopFriendsUrl = (params?: GetTopFriendsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/stats/top-friends?${stringifiedParams}`
    : `/api/stats/top-friends`;
};

export const getTopFriends = async (
  params?: GetTopFriendsParams,
  options?: RequestInit,
): Promise<FriendSummary[]> => {
  return customFetch<FriendSummary[]>(getGetTopFriendsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetTopFriendsQueryKey = (params?: GetTopFriendsParams) => {
  return [`/api/stats/top-friends`, ...(params ? [params] : [])] as const;
};

